# Game Engine
class Engine:
    def __init__(self):
        self.running = False
        self.fps = 60
        self.frame = 0

    def start(self):
        self.running = True
        self.loop()

    def loop(self):
        while self.running:
            self.update()
            self.render()
            self.frame += 1

    def update(self):
        pass

    def render(self):
        pass

    def stop(self):
        self.running = False
        print(f"Stopped at {self.frame}")

    def reset(self):
        self.frame = 0
        self.running = False
